const AUTO_FIX_ALLOWLIST = new Set(['NtfyBridgeDown','KubePodCrashLoopBackOff','KubePodOOMKilled','MonitoringVMAlertDown','MonitoringAlertmanagerDown']);
const expectedSecret = $env.WEBHOOK_SECRET || '';
const gotSecret = $input.first().json.params?.webhookSecret || $input.first().json.query?.webhookSecret || $input.first().json.headers?.['x-webhook-secret'] || '';
if (expectedSecret && gotSecret !== expectedSecret) {
  throw new Error('Invalid webhook secret');
}
const body = $input.first().json.body ?? $input.first().json;
const alerts = body.alerts || [];
const first = alerts[0] || {};
const labels = { ...(body.commonLabels || {}), ...(first.labels || {}) };
const annotations = { ...(body.commonAnnotations || {}), ...(first.annotations || {}) };
const alertname = labels.alertname || body.groupLabels?.alertname || 'Unknown';
const autoTriage = labels['homelab/auto_triage'] === 'true' || labels['homelab_auto_remediate'] === 'true';
const allowAutoFix = autoTriage && AUTO_FIX_ALLOWLIST.has(alertname);
return [{
  json: {
    status: body.status || 'firing',
    alertname,
    severity: labels.severity || 'warning',
    namespace: labels.namespace || '',
    instance: labels.instance || labels.pod || '',
    cluster: labels.cluster || 'homelab',
    owner: labels['homelab/owner'] || '',
    autoTriage,
    allowAutoFix,
    runbookUrl: annotations.runbook_url || '',
    summary: annotations.summary || '',
    description: annotations.description || '',
    alertCount: alerts.length,
    fingerprint: first.fingerprint || '',
    raw: body,
  },
}];

const a = $input.first().json;
const text = `✅ *RESOLVED*

*${a.alertname}*
${a.summary || ''}

_ns:_ ${a.namespace || '—'}_`;
return [{ json: { telegramText: text, parseMode: 'Markdown' } }];

