const alert = $('Parse Alert').first().json;
let triage = {};
try {
  const raw = $input.first().json.message?.content ?? $input.first().json.text ?? $input.first().json.output ?? '';
  const m = String(raw).match(/\{[\s\S]*\}/);
  triage = m ? JSON.parse(m[0]) : { outcome: 'cannot_fix', summary_de: 'LLM-Antwort nicht parsebar', action_needed: true };
} catch (e) {
  triage = { outcome: 'cannot_fix', summary_de: 'LLM parse error: ' + e.message, action_needed: true, automatable: false };
}
const mayAutoFix = alert.allowAutoFix && triage.automatable === true && triage.outcome === 'auto_fix_candidate';
return [{ json: { ...alert, triage, mayAutoFix } }];

const a = $('Parse Root Cause').first().json;
const rem = $input.first().json;
const httpCode = rem.statusCode || rem.httpCode || (rem.error ? 500 : 200);
const ok = httpCode >= 200 && httpCode < 300;
const body = typeof rem.body === 'string' ? JSON.parse(rem.body) : (rem.body || rem);
const fix = body.git_commit || {};
let text;
if (ok) {
  text = '🔧 *Auto-Fix ausgeführt*\n\n*' + a.alertname + '*\n' + (a.summary_de || '') + '\n\n';
  if (a.memory_suggested) text += 'Memory: ' + (a.memory_current || '?') + ' \u2192 ' + a.memory_suggested + '\n';
  if (a.cpu_suggested) text += 'CPU: ' + (a.cpu_current || '?') + ' \u2192 ' + a.cpu_suggested + '\n';
  text += 'Deployment: ' + a.deployment_name + '\n';
  text += 'Git-Commit: ' + (fix.committed ? '✅ committed' : '❌ fehlgeschlagen') + '\n';
  text += '\n_audit: ' + (body.audit_id || '—') + '_';
} else {
  text = '⚠️ *Auto-Fix fehlgeschlagen*\n\n*' + a.alertname + '*\n' + (a.summary_de || '') + '\n\nHTTP ' + httpCode + ' \u2014 ' + (body.message || JSON.stringify(body).slice(0,200)) + '\n\n*Human-in-the-Loop*: manuell eingreifen.';
}
return [{ json: { telegramText: text, parseMode: 'Markdown' } }];

// Input either from needs_human path or from auto_fix investigate-only path
const input = $input.first().json;
let text;

if (input.alertname && input.root_cause) {
  // investigate-only format
  const emoji = { CONFIG_ERROR: '⚠️', IMAGE_ERROR: '📦', DEPENDENCY: '🔗', UNKNOWN: '❓', OOM: '💥' }[input.root_cause] || 'ℹ️';
  text = emoji + ' *Investigation abgeschlossen - kein Auto-Fix*\n\n';
  text += '*Alarm:* ' + input.alertname + '\n';
  text += '*Root Cause:* ' + input.root_cause + ' (confidence: ' + input.confidence + ')\n';
  text += '*Deployment:* ' + input.deployment_name + '\n';
  if (input.summary_de) text += '\n' + input.summary_de + '\n';
  if (input.recommended_action) text += '\nHandlungsempfehlung: ' + input.recommended_action;
} else {
  // Original needs_human / cannot_fix format
  text = $json.telegramText || input.telegramText || 'Investigation abgeschlossen.';
}
return [{ json: { telegramText: text, parseMode: 'Markdown' } }];

const alert = $('Merge Triage').first().json;
const inv = $('Call Investigate').first().json;
let rc = {};
try {
  const raw = $input.first().json.message?.content ?? $input.first().json.text ?? $input.first().json.output ?? '';
  const m = String(raw).match(/\{[\s\S]*\}/);
  rc = m ? JSON.parse(m[0]) : { root_cause: 'UNKNOWN', confidence: 'low', summary_de: 'LLM-Antwort nicht parsebar' };
} catch (e) {
  rc = { root_cause: 'UNKNOWN', confidence: 'low', summary_de: 'LLM parse error: ' + e.message };
}
const owner = inv.owner || {};
const podName = alert.instance || '';
const depName = owner.name || podName.replace(/-[a-z0-9]{5,10}-[a-z0-9]{5}$/, '').replace(/-[0-9]+$/, '');
return [{
  json: {
    root_cause: rc.root_cause || 'UNKNOWN',
    confidence: rc.confidence || 'low',
    fix_type: rc.fix_type || 'none',
    summary_de: rc.summary_de || '',
    recommended_action: rc.recommended_action || '',
    memory_current: rc.memory_current || '',
    memory_suggested: rc.memory_suggested || '',
    cpu_current: rc.cpu_current || '',
    cpu_suggested: rc.cpu_suggested || '',
    alertname: alert.alertname,
    namespace: alert.namespace,
    instance: alert.instance,
    deployment_name: depName,
  }
}];

